diff --git a/packages/cf-component-form/test/FormFieldError.js b/packages/cf-component-form/test/FormFieldError.js
index 1865203..5324f75 100644
--- a/packages/cf-component-form/test/FormFieldError.js
+++ b/packages/cf-component-form/test/FormFieldError.js
@@ -1,27 +1,34 @@
 import React from 'react';
 import renderer from 'react-test-renderer';
 import { renderToStaticMarkup } from 'react-dom/server';
-import { FormFieldError } from '../../cf-component-form/src/index';
+import { FormFieldError } from '../src/index';
+import felaTestContext from '../../../felaTestContext';

 test('should render valid state', () => {
   expect(
-    renderToStaticMarkup(<FormFieldError field={{}} validations={{}} />)
+    renderToStaticMarkup(
+      felaTestContext(<FormFieldError field={{}} validations={{}} />)
+    )
   ).toBe('');
 });

 test('should render invalid state', () => {
   const component = renderer.create(
-    <FormFieldError field={{ invalid: true }} validations={{}} />
+    felaTestContext(
+      <FormFieldError field={{ invalid: true }} validations={{}} />
+    )
   );
   expect(component.toJSON()).toMatchSnapshot();
 });

 test('should render invalid state with validation errors', () => {
   const component = renderer.create(
-    <FormFieldError
-      field={{ invalid: true }}
-      validations={{ required: 'This is required' }}
-    />
+    felaTestContext(
+      <FormFieldError
+        field={{ invalid: true }}
+        validations={{ required: 'This is required' }}
+      />
+    )
   );
   expect(component.toJSON()).toMatchSnapshot();
 });

