diff --git a/packages/cf-style-container/test/index.js b/packages/cf-style-container/test/index.js
index 660bd82..d8eb105 100644
--- a/packages/cf-style-container/test/index.js
+++ b/packages/cf-style-container/test/index.js
@@ -1,6 +1,7 @@
 import React, { PropTypes } from 'react';
 import {
   createComponent,
+  createComponentStyles,
   applyTheme,
   ThemeProvider,
   color
@@ -31,3 +32,22 @@ test('createComponent creates empty component', () => {
   const component = renderer.create(felaTestContext(<FelaComponent />));
   expect(component.toJSON()).toMatchSnapshot();
 });
+
+test('createComponentStyles creates a component', () => {
+  const Foo = ({ styles }) => (
+    <div className={styles.class1}><i classNames={styles.class2} /></div>
+  );
+  const FelaComponent = createComponentStyles(
+    {
+      class1: () => ({
+        padding: '5px'
+      }),
+      class2: () => ({
+        margin: '2px'
+      })
+    },
+    Foo
+  );
+  const component = renderer.create(felaTestContext(<FelaComponent />));
+  expect(component.toJSON()).toMatchSnapshot();
+});

