diff --git a/packages/cf-component-page/test/Header.js b/packages/cf-component-page/test/Header.js
new file mode 100644
index 0000000..3d80fb3
--- /dev/null
+++ b/packages/cf-component-page/test/Header.js
@@ -0,0 +1,16 @@
+import React from 'react';
+import renderer from 'react-test-renderer';
+import Header from '../src/Header';
+import { felaSnapshot } from 'cf-style-provider';
+
+test('should render', () => {
+  const snapshot = felaSnapshot(<Header>Hello World</Header>);
+  expect(snapshot.component).toMatchSnapshot();
+  expect(snapshot.styles).toMatchSnapshot();
+});
+
+test('should render sticky', () => {
+  const snapshot = felaSnapshot(<Header sticky>Hello World</Header>);
+  expect(snapshot.component).toMatchSnapshot();
+  expect(snapshot.styles).toMatchSnapshot();
+});

